package com.example.knowledgecollector.web.security;
import com.example.knowledgecollector.application.security.*;import jakarta.servlet.http.HttpServletResponse;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.context.annotation.*;import org.springframework.http.MediaType;import org.springframework.security.authentication.LockedException;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.core.userdetails.*;import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.security.web.SecurityFilterChain;import java.io.IOException;
@Configuration @ConditionalOnProperty(name="knowledge-collector.security.enabled",havingValue="true",matchIfMissing=true) public class SecurityConfiguration {
 @Bean UserDetailsService userDetails(UserService users,LoginAttemptService attempts){return name->{if(attempts.blocked(name))throw new LockedException("登录尝试过多，请10分钟后再试");UserCredentials u=users.credentials(name);if(u==null)throw new UsernameNotFoundException("用户名或密码错误");return User.withUsername(u.username()).password(u.passwordHash()).roles(u.role()).disabled(!u.enabled()).build();};}
 @Bean PasswordEncoder passwordEncoder(){return new BCryptPasswordEncoder(12);}
 @Bean SecurityFilterChain security(HttpSecurity http,UserService users,LoginAttemptService attempts)throws Exception {http.authorizeHttpRequests(a->a.requestMatchers("/login","/access-denied","/favicon.ico","/css/**","/js/login.js","/actuator/health","/error").permitAll().requestMatchers("/users/**","/third-party-systems/**","/capabilities/**","/operations/**","/tasks/**","/sources/**","/topics/**","/extractions/**","/evidence-files/**","/advanced/**","/test-console/**","/api/v1/users/**","/api/v1/external-systems/**","/api/v1/capabilities/**","/api/v1/operations/**","/api/v1/tasks/**","/api/v1/sources/**","/api/v1/topics/**","/api/v1/extractions/**","/api/v1/evidence-files/**","/api/v1/advanced/**","/api/v1/dev/**","/swagger-ui/**","/v3/api-docs/**").hasRole("ADMIN").anyRequest().authenticated()).formLogin(f->f.loginPage("/login").successHandler((req,res,auth)->{attempts.success(auth.getName());UserCredentials u=users.credentials(auth.getName());if(u!=null)users.recordLogin(u.id());res.sendRedirect("/");}).failureHandler((req,res,e)->{attempts.failure(req.getParameter("username"));res.sendRedirect("/login?error");}).permitAll()).logout(l->l.logoutUrl("/logout").logoutSuccessUrl("/login?logout").invalidateHttpSession(true).deleteCookies("JSESSIONID")).exceptionHandling(e->e.accessDeniedPage("/access-denied").authenticationEntryPoint((req,res,ex)->{if(req.getRequestURI().startsWith("/api/"))json(res,401,"AUTH-401","请先登录");else res.sendRedirect("/login");}).accessDeniedHandler((req,res,ex)->{if(req.getRequestURI().startsWith("/api/"))json(res,403,"AUTH-403","无权执行此操作");else res.sendRedirect("/access-denied");})).csrf(c->c.ignoringRequestMatchers("/api/**"));return http.build();}
 private static void json(HttpServletResponse r,int status,String code,String message)throws IOException{r.setStatus(status);r.setCharacterEncoding("UTF-8");r.setContentType(MediaType.APPLICATION_JSON_VALUE);r.getWriter().write("{\"success\":false,\"data\":null,\"error\":{\"code\":\""+code+"\",\"message\":\""+message+"\",\"fieldErrors\":[]}}");}
}
